type Success<T> = { status: 'success'; data: T };
type Failure<E> = { status: 'failure'; error: E };

type Result<T, E> = Success<T> | Failure<E>;

type ExtractError<T> = T extends Failure<infer E> ? E : never;

// Usage example:
type MyError = ExtractError<Result<string, Error>>;  // MyError is of type Error

type ExtractSuccess<T> = T extends Success<infer D> ? D : never;

type ExtractFailures<T> = T extends Failure<infer E> ? E : never;

// Combined example:
type AllSuccessData = ExtractSuccess<Result<string, number> | Result<boolean, string>>;
// AllSuccessData is string | boolean

type AllErrors = ExtractFailures<Result<string, number> | Result<boolean, string>>;
// AllErrors is number | string

function handleResult<T, E>(result: Result<T, E>): T {
  if (result.status === 'failure') {
    throw result.error;
  }
  return result.data;
}

// Usage example:
const response: Result<string, Error> = { status: 'failure', error: new Error('Network issue') };

try {
  const data = handleResult(response);
  console.log(data);
} catch (e) {
  console.error('Caught error:', e.message);
}

import time
import requests

API_URL = "https://api.example.com/data"


def fetch_data():
    while True:
        response = requests.get(API_URL)

        if response.status_code == 200:
            print("Data fetched successfully!")
            return response.json()
        elif response.status_code == 429:
            # Rate limit hit; wait before retrying
            retry_after = int(response.headers.get("Retry-After", 5))
            print(f"Rate limit exceeded. Retrying in {retry_after} seconds...")
            time.sleep(retry_after)
        else:
            # Handle other errors
            print(f"Failed with status code: {response.status_code}")
            return None


if __name__ == "__main__":
    data = fetch_data()
